mapper.select:
SELECT l.lecture_id AS lectureId, l.member_code AS memberCode, l.status, l.lecture_type AS lectureType, l.lecture_name AS lectureName, mj.name AS majorName, pc.name AS proName, l.credit, l.academic_year AS academicYear, l.year, l.semester, ls.day_of_week AS dayOfWeek, ls.start_period AS startPeriod, ls.end_period AS endPeriod, lr.building, lr.room AS room FROM lecture l LEFT JOIN professor_cache pc ON l.member_code = pc.member_code LEFT JOIN major mj ON l.major_id = mj.major_id LEFT JOIN lecture_schedule ls ON l.lecture_id = ls.lecture_id LEFT JOIN classroom lr ON ls.room_id = lr.room_id
AND l.status = #{status}
ORDER BY l.lecture_id DESC LIMIT #{size} OFFSET #{startIdx}

SELECT l.lecture_id AS lectureId, l.member_code AS memberCode, l.status, l.lecture_type AS lectureType, l.lecture_name AS lectureName, mj.name AS majorName, pc.name AS proName, l.credit, l.academic_year AS academicYear, l.year, l.semester, ls.day_of_week AS dayOfWeek, ls.start_period AS startPeriod, ls.end_period AS endPeriod, lr.building, lr.room AS room FROM lecture l LEFT JOIN professor_cache pc ON l.member_code = pc.member_code LEFT JOIN major mj ON l.major_id = mj.major_id LEFT JOIN lecture_schedule ls ON l.lecture_id = ls.lecture_id LEFT JOIN classroom lr ON ls.room_id = lr.room_id WHERE l.member_code = #{memberCode}
AND l.lecture_name LIKE CONCAT('%', #{req.lectureName}, '%')
AND l.year = #{req.year} AND l.semester = #{req.semester} ORDER BY l.lecture_id DESC LIMIT #{req.size} OFFSET #{req.startIdx}
